from flask import Flask
from flask_graphql import GraphQLView
from graphene import ObjectType, String, Schema, List, Field, Int

class Product(ObjectType):
    id = Int()
    name = String()
    price = String()
    category = String()

class Category(ObjectType):
    id = Int()
    name = String()

class Review(ObjectType):
    id = Int()
    user_id = Int()
    product_id = Int()
    review_text = String()
    rating = Int()

class Query(ObjectType):
    products = List(Product)
    categories = List(Category)
    reviews = List(Review, product_id=Int())

    def resolve_products(self, info):
        # Replace with data retrieval logic
        return [
            Product(id=1, name="Laptop", price="1000", category="Electronics"),
            Product(id=2, name="Shirt", price="20", category="Clothing"),
        ]

    def resolve_categories(self, info):
        # Replace with data retrieval logic
        return [
            Category(id=1, name="Electronics"),
            Category(id=2, name="Clothing"),
        ]

    def resolve_reviews(self, info, product_id=None):
        # Replace with data retrieval logic
        reviews = [
            Review(id=1, user_id=101, product_id=1, review_text="Great product", rating=5),
            Review(id=2, user_id=102, product_id=2, review_text="Good quality", rating=4),
        ]
        if product_id:
            reviews = [review for review in reviews if review.product_id == product_id]
        return reviews

schema = Schema(query=Query)

app = Flask(__name__)
app.add_url_rule(
    "/graphql", view_func=GraphQLView.as_view("graphql", schema=schema, graphiql=True)
)

if __name__ == "__main__":
    app.run(debug=True)